import sailpoint.object.Application;
  import sailpoint.object.Identity;
  import sailpoint.object.Link;
  import sailpoint.object.Filter;
  import sailpoint.object.QueryOptions;
  import sailpoint.tools.Util;
  import sailpoint.api.IdentityService;

  private String getPrincipalName(Identity identity) {
    
    IdentityService iService = new IdentityService(context);
    
    QueryOptions ops = new QueryOptions();
    ops.addFilter(Filter.eq("type","Active Directory - Direct"));
    
    List adApps = context.getObjects(Application.class, ops);

    List links = iService.getLinks(identity, adApps, null);
    String samAccountName = identity.getAttribute("samAccountName");
    boolean managerStatus = identity.getManagerStatus();
    Date whenCreated = identity.getCreated();

    Date logicStartsAt = new Date(new Long("1617253200000")); //Only Identities Created After This UNIX Time Should Be Considered.

    //Check 1 - Proceed when samAccountName is populated; managerStatus is true; Identity is not inactive; and whenCreated is after logicStartsAt.

    if (Util.isNotNullOrEmpty(samAccountName) && managerStatus && !identity.isInactive() && Util.isDateAfter(whenCreated, logicStartsAt)) {

      if(links != null){

        //Check 2 - Compare the samAccountName attribute of each AD link to the corresponding Identity Attribute; return msDS-PrincipalName if a match is found.

        for(Link link : links){

          if(link.getApplication().getType().equalsIgnoreCase("Active Directory - Direct")){

            if(link.getAttribute("sAMAccountName").equalsIgnoreCase(samAccountName)){

              String principalName = link.getAttribute("msDS-PrincipalName");

              if (Util.isNotNullOrEmpty(principalName)) {

                return principalName;

              }

            }

          }

        }

      }

    }

    return "";

  }

  private void netBiosAdjustment(String netBios) {

    //Adjust Complex Domain NetBIOS to Common Ministry Identifier

    if (Util.nullSafeCaseInsensitiveEq(netBios, "CRITTENTON-NET")) {

      super.netBios = "MIROC";

    }

    if (Util.nullSafeCaseInsensitiveEq(netBios, "MEDXCELFM")) {

      super.netBios = "AHMFM";

    }

    if (Util.nullSafeCaseInsensitiveEq(netBios, "VCHS_NT_DOMAIN")) {

      super.netBios = "KSWIC";

    }

  }

  private boolean shouldReceiveNARSManagerAccess(String principalName) {

    //Get everything before the backslash in the msDS-PrincipalName to determine NetBIOS of Domain.

    netBios = principalName.replaceAll("\\\\.*.","");

    if (Util.isNotNullOrEmpty(netBios)) {

      netBiosAdjustment(netBios);

      if (roleName.contains(netBios)) {

        //roleName of NARS Manager Access Roles should contain the NetBIOS value of the relevant domain; further conditional checks are not needed here, as they are covered by the getPrincipalName(Identity identity) method.

        return true;

      } 

    }

    return false;

  }

  static String netBios;

  String principalName = getPrincipalName(identity);

  if (Util.isNotNullOrEmpty(principalName)) {

    return shouldReceiveNARSManagerAccess(principalName);

  }

  return false;
